#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        char S[10], B[50][50];
        scanf("%d %s", &N, S);
        for (int i = 0; i < N; i++) {
            scanf("%s", B[i]);
        }
        int ones = 0, zeros = 0;
        for (int i = 0; i < N; i++) {
            int count = 0;
            for (int j = 0; j < strlen(B[i]); j++) {
                if (B[i][j] == '1') {
                    count++;
                }
            }
            ones ^= count;
            count = 0;
            for (int j = 0; j < strlen(B[i]); j++) {
                if (B[i][j] == '0') {
                    count++;
                }
            }
            zeros ^= count;
        }
        if (strcmp(S, "Dee") == 0) {
            if (ones == 0 && zeros == 0) {
                printf("Dum\n");
            } else {
                printf("Dee\n");
            }
        } else {
            if (ones == 0 && zeros == 0) {
                printf("Dee\n");
            } else {
                printf("Dum\n");
            }
        }
    }
    return 0;
}

